#!/bin/bash

# ==================== GitLab Runner Setup Script ====================
# Script tự động setup GitLab Runner trên EC2
# ====================================================================

set -e

echo "🚀 GitLab Runner Setup Script"
echo "============================"

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m'

# Check if running as root
if [ "$EUID" -eq 0 ]; then
    echo -e "${RED}❌ Please do not run as root. Use ec2-user.${NC}"
    exit 1
fi

# Step 1: Install GitLab Runner
echo ""
echo -e "${GREEN}Step 1: Installing GitLab Runner...${NC}"

if command -v gitlab-runner &> /dev/null; then
    echo -e "${GREEN}✅ GitLab Runner already installed${NC}"
    gitlab-runner --version
else
    # Download GitLab Runner repository
    curl -L "https://packages.gitlab.com/install/repositories/runner/gitlab-runner/script.rpm.sh" | sudo bash
    
    # Install GitLab Runner
    sudo yum install gitlab-runner -y
    
    # Start and enable GitLab Runner
    sudo systemctl start gitlab-runner
    sudo systemctl enable gitlab-runner
    
    echo -e "${GREEN}✅ GitLab Runner installed${NC}"
    gitlab-runner --version
fi

# Step 2: Install Docker (if not installed)
echo ""
echo -e "${GREEN}Step 2: Checking Docker installation...${NC}"

if command -v docker &> /dev/null; then
    echo -e "${GREEN}✅ Docker already installed${NC}"
    docker --version
else
    echo -e "${YELLOW}⚠️  Docker not found. Installing...${NC}"
    sudo yum install docker -y
    sudo systemctl start docker
    sudo systemctl enable docker
    sudo usermod -aG docker $USER
    sudo usermod -aG docker gitlab-runner
    echo -e "${GREEN}✅ Docker installed${NC}"
fi

# Step 3: Add gitlab-runner to docker group
echo ""
echo -e "${GREEN}Step 3: Configuring Docker permissions...${NC}"
sudo usermod -aG docker gitlab-runner
sudo systemctl restart gitlab-runner
echo -e "${GREEN}✅ Docker permissions configured${NC}"

